  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider     = \"prisma-client\"\n  output       = \"./generated/prisma\"\n  moduleFormat = \"commonjs\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ─────────────────────────────────────────────\n// USER & CREDIT CARD\n// ─────────────────────────────────────────────\n\nmodel User {\n  id           String   @id @default(uuid())\n  name         String\n  email        String   @unique\n  hashPassword String\n  birthDate    DateTime\n\n  creditCards          CreditCard[]\n  statements           Statement[]\n  expenses             Expense[]\n  categories           Category[]\n  refreshTokens        RefreshToken[]\n  forgotPasswordTokens PasswordResetToken[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel CreditCard {\n  id             String @id @default(uuid())\n  name           String\n  userId         String\n  lastFourDigits String\n  closingDay     Int\n  dueDay         Int\n\n  user       User        @relation(fields: [userId], references: [id])\n  statements Statement[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([userId])\n}\n\n// ─────────────────────────────────────────────\n// STATEMENT\n// ─────────────────────────────────────────────\n\nmodel Statement {\n  id             String   @id @default(uuid())\n  userId         String // desnormalizado para queries diretas por usuário\n  creditCardId   String\n  referenceMonth DateTime // sempre salvar como primeiro dia do mês (ex: 2024-01-01)\n  filePath       String? // caminho/chave do PDF no storage\n\n  status StatementStatus @default(UPLOADED)\n\n  // Resposta bruta do Gemini — útil para debug e reprocessamento\n  rawAiResponse Json?\n\n  // Metadados extraídos pelo Gemini\n  totalAmount Decimal?  @db.Decimal(10, 2)\n  dueDate     DateTime?\n\n  user       User            @relation(fields: [userId], references: [id])\n  creditCard CreditCard      @relation(fields: [creditCardId], references: [id])\n  expenses   Expense[]\n  logs       ProcessingLog[]\n\n  createdAt   DateTime  @default(now())\n  processedAt DateTime?\n\n  @@unique([creditCardId, referenceMonth])\n  @@index([userId])\n  @@index([status])\n  @@index([creditCardId])\n}\n\n// ─────────────────────────────────────────────\n// EXPENSE\n// ─────────────────────────────────────────────\n\nmodel Expense {\n  id          String @id @default(uuid())\n  userId      String // desnormalizado para queries diretas por usuário\n  statementId String\n\n  date                  DateTime\n  descriptionOriginal   String // texto exato da fatura\n  descriptionNormalized String // normalizado pelo Gemini\n  merchantName          String? // merchant identificado pelo Gemini\n\n  amount Decimal @db.Decimal(10, 2)\n\n  installmentCurrent Int?\n  installmentTotal   Int?\n\n  // Categoria definida pela IA vs corrigida manualmente pelo usuário\n  categoryAutoId   String\n  categoryManualId String?\n\n  // Hash para deduplicação na reingestão de faturas\n  hashUnique String\n\n  user           User      @relation(fields: [userId], references: [id])\n  statement      Statement @relation(fields: [statementId], references: [id], onDelete: Cascade)\n  categoryAuto   Category  @relation(\"AutoCategory\", fields: [categoryAutoId], references: [id])\n  categoryManual Category? @relation(\"ManualCategory\", fields: [categoryManualId], references: [id])\n\n  createdAt DateTime @default(now())\n\n  @@unique([statementId, hashUnique])\n  @@index([userId])\n  @@index([statementId])\n  @@index([categoryAutoId])\n  @@index([date])\n}\n\n// ─────────────────────────────────────────────\n// CATEGORY\n// ─────────────────────────────────────────────\n\nmodel Category {\n  id   String       @id @default(uuid())\n  name String\n  type CategoryType\n\n  // userId nulo = categoria de sistema (compartilhada entre todos)\n  // userId preenchido = categoria do usuário (isolada)\n  userId String?\n  user   User?   @relation(fields: [userId], references: [id])\n\n  autoExpenses   Expense[] @relation(\"AutoCategory\")\n  manualExpenses Expense[] @relation(\"ManualCategory\")\n\n  @@unique([name, type, userId])\n  @@index([userId])\n}\n\nenum CategoryType {\n  SYSTEM // categorias padrão do sistema, userId sempre nulo\n  USER // categorias criadas pelo usuário, userId sempre preenchido\n}\n\n// ─────────────────────────────────────────────\n// PROCESSING LOG\n// ─────────────────────────────────────────────\n\nmodel ProcessingLog {\n  id          String @id @default(uuid())\n  statementId String\n\n  step    PipelineStep\n  status  LogStatus\n  message String?\n\n  executionTimeMs Int?\n\n  statement Statement @relation(fields: [statementId], references: [id])\n\n  createdAt DateTime @default(now())\n\n  @@index([statementId])\n}\n\n// Auth refreshTokens\n\nmodel RefreshToken {\n  id        String   @id @default(uuid())\n  userId    String\n  tokenHash String   @unique\n  expiresAt DateTime\n  createdAt DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id])\n\n  @@index([userId])\n}\n\n//\n\nmodel PasswordResetToken {\n  id        String   @id @default(uuid())\n  userId    String\n  tokenHash String   @unique\n  expiresAt DateTime\n  createdAt DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id])\n\n  @@index([userId])\n}\n\n// ─────────────────────────────────────────────\n// ENUMS\n// ─────────────────────────────────────────────\n\nenum StatementStatus {\n  UPLOADED // PDF recebido\n  PROCESSING // enviado ao Gemini, aguardando resposta\n  PROCESSED // despesas persistidas com sucesso\n  FAILED // erro em alguma etapa\n}\n\nenum PipelineStep {\n  UPLOAD // recebimento do PDF\n  AI_EXTRACTION // chamada ao Gemini (extração + normalização + categorização)\n  PERSISTENCE // gravação das despesas no banco\n}\n\nenum LogStatus {\n  SUCCESS\n  ERROR\n}\n",
